        consecutiveLoadFailures += 1;
        if (consecutiveLoadFailures < MAX_CONSECUTIVE_LOAD_FAILURES && lastPayload?.state === "ready") {
          return;
        }
        everLoaded = true;
        lastPayload = { state: "empty", subtitle: SMART_TASK_WIDGET_LOAD_ERROR_SUBTITLE, hint: null };
        view = { kind: "list" };
